1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Damage[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = { customer: Customer; steps: Step[] };
9	
10	const DEDUCTIBLE = 100;
11	const CAP_MULTIPLIER = 2;
12	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
13	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
14	
15	const PROCESSING_FEE = 5;
16	const FIRST_INSURANCE_SURCHARGE = 0.1;
17	const CURSE_SURCHARGE = 0.5;
18	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	const LOYALTY_DISCOUNT = 0.2;
21	const LOYALTY_YEARS_THRESHOLD = 2;
22	const FOLLOWUP_DISCOUNT = 0.15;
23	const COMPONENT_BASE_PREMIUM = 25;
24	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_INSURANCE_VALUE = 250;
27	
28	type Tariff = { base: number; insurance: number };
29	
30	const MAIN_ITEM_TARIFF: Record<string, Tariff> = {
31	  sword: { base: 100, insurance: 1000 },
32	  amulet: { base: 60, insurance: 600 },
33	};
34	
35	const KNOWN_COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	
37	const isMainItem = (item: Item): boolean => item.type in MAIN_ITEM_TARIFF;
38	
39	const isKnownItemType = (type: string): boolean =>
40	  type in MAIN_ITEM_TARIFF || KNOWN_COMPONENT_TYPES.has(type);
41	
42	const assertNoneMatch = <T>(items: T[], predicate: (item: T) => boolean, message: (item: T) => string): void => {
43	  const offender = items.find(predicate);
44	  if (offender) throw new Error(message(offender));
45	};
46	
47	const assertKnownItemTypes = (items: Item[]): void =>
48	  assertNoneMatch(
49	    items,
50	    (item) => !isKnownItemType(item.type),
51	    (item) => `Unknown item type: ${item.type}`,
52	  );
53	
54	const itemInsuranceValue = (item: Item): number =>
55	  MAIN_ITEM_TARIFF[item.type]?.insurance ?? COMPONENT_INSURANCE_VALUE;
56	
57	const ceilWithEpsilon = (n: number): number => Math.ceil(Math.round(n * 1e8) / 1e8);
58	
59	const sumBy = <T>(items: T[], valueOf: (item: T) => number): number =>
60	  items.reduce((sum, item) => sum + valueOf(item), 0);
61	
62	const rateAmount = (base: number, applies: boolean, rate: number): number =>
63	  applies ? base * rate : 0;
64	
65	const enchantmentLevel = (item: Item | undefined): number => item?.enchantment ?? 0;
66	
67	const isHighlyEnchanted = (item: Item): boolean =>
68	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
69	
70	const mainItemBase = (item: Item): number => MAIN_ITEM_TARIFF[item.type].base;
71	
72	const mainItemSurcharges = (item: Item): number => {
73	  const base = mainItemBase(item);
74	  return (
75	    rateAmount(base, item.cursed === true, CURSE_SURCHARGE) +
76	    rateAmount(base, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE)
77	  );
78	};
79	
80	const componentGroupBase = (count: number): number => {
81	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
82	  const leftover = count % COMPONENT_BLOCK_SIZE;
83	  return blocks * COMPONENT_BLOCK_BASE_PREMIUM + leftover * COMPONENT_BASE_PREMIUM;
84	};
85	
86	const componentCountsByType = (components: Item[]): Map<string, number> => {
87	  const counts = new Map<string, number>();
88	  for (const item of components) {
89	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
90	  }
91	  return counts;
92	};
93	
94	const sumComponentGroupBases = (components: Item[]): number =>
95	  sumBy([...componentCountsByType(components).values()], componentGroupBase);
96	
97	const partitionItems = (items: Item[]): { mainItems: Item[]; components: Item[] } => ({
98	  mainItems: items.filter(isMainItem),
99	  components: items.filter((item) => !isMainItem(item)),
100	});
101	
102	const sumMainItemBases = (mainItems: Item[]): number => sumBy(mainItems, mainItemBase);
103	
104	const sumMainItemSurcharges = (mainItems: Item[]): number => sumBy(mainItems, mainItemSurcharges);
105	
106	const isLoyalCustomer = (customer: Customer): boolean =>
107	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
108	
109	const totalDiscount = (policyBase: number, customer: Customer, isFollowUp: boolean): number =>
110	  rateAmount(policyBase, isLoyalCustomer(customer), LOYALTY_DISCOUNT) +
111	  rateAmount(policyBase, isFollowUp, FOLLOWUP_DISCOUNT);
112	
113	const priceQuote = (step: QuoteStep, customer: Customer, isFollowUp: boolean): { premium: number } => {
114	  assertKnownItemTypes(step.items);
115	  const { mainItems, components } = partitionItems(step.items);
116	  const policyBase = sumMainItemBases(mainItems) + sumComponentGroupBases(components);
117	  const surcharges = sumMainItemSurcharges(mainItems);
118	  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE;
119	  const discounts = totalDiscount(policyBase, customer, isFollowUp);
120	  return {
121	    premium: ceilWithEpsilon(policyBase + surcharges + firstInsurance - discounts + PROCESSING_FEE),
122	  };
123	};
124	
125	const countQuotesBefore = (steps: Step[], index: number): number =>
126	  steps.slice(0, index).filter((s) => s.op === "quote").length;
127	
128	const insuranceSumOf = (step: QuoteStep): number => sumBy(step.items, itemInsuranceValue);
129	
130	const findInsuredItem = (policyStep: QuoteStep, itemType: string): Item | undefined =>
131	  policyStep.items.find((item) => item.type === itemType);
132	
133	const reimbursementRate = (item: Item | undefined): number =>
134	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
135	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
136	    : 1;
137	
138	const damagePayout = (damage: Damage, policyStep: QuoteStep): number => {
139	  const item = findInsuredItem(policyStep, damage.itemType);
140	  return Math.max(0, damage.amount * reimbursementRate(item) - DEDUCTIBLE);
141	};
142	
143	const totalPayout = (damages: Damage[], policyStep: QuoteStep): number =>
144	  sumBy(damages, (d) => damagePayout(d, policyStep));
145	
146	const initialCap = (policyStep: QuoteStep): number =>
147	  CAP_MULTIPLIER * insuranceSumOf(policyStep);
148	
149	const assertDamagesInPolicy = (damages: Damage[], policyStep: QuoteStep): void =>
150	  assertNoneMatch(
151	    damages,
152	    (d) => !findInsuredItem(policyStep, d.itemType),
153	    (d) => `Damage references item not in policy: ${d.itemType}`,
154	  );
155	
156	const assertNonNegativeDamages = (damages: Damage[]): void =>
157	  assertNoneMatch(
158	    damages,
159	    (d) => d.amount < 0,
160	    (d) => `Damage amount must be non-negative: ${d.amount}`,
161	  );
162	
163	const damageCountsByType = (damages: Damage[]): Map<string, number> => {
164	  const counts = new Map<string, number>();
165	  for (const d of damages) {
166	    counts.set(d.itemType, (counts.get(d.itemType) ?? 0) + 1);
167	  }
168	  return counts;
169	};
170	
171	const insuredCountsByType = (policyStep: QuoteStep): Map<string, number> => {
172	  const counts = new Map<string, number>();
173	  for (const item of policyStep.items) {
174	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
175	  }
176	  return counts;
177	};
178	
179	const assertDamageCountsWithinPolicy = (damages: Damage[], policyStep: QuoteStep): void => {
180	  const insured = insuredCountsByType(policyStep);
181	  const damaged = damageCountsByType(damages);
182	  for (const [itemType, count] of damaged) {
183	    if (count > (insured.get(itemType) ?? 0)) {
184	      throw new Error(`More damage entries for ${itemType} than items insured`);
185	    }
186	  }
187	};
188	
189	const validateClaim = (damages: Damage[], policyStep: QuoteStep): void => {
190	  assertNonNegativeDamages(damages);
191	  assertDamagesInPolicy(damages, policyStep);
192	  assertDamageCountsWithinPolicy(damages, policyStep);
193	};
194	
195	const processClaim = (
196	  step: ClaimStep,
197	  steps: Step[],
198	  remainingCaps: Map<number, number>,
199	): { payout: number; remainingCap: number } => {
200	  const policyStep = steps[step.policy] as QuoteStep;
201	  validateClaim(step.incident.damages, policyStep);
202	  const availableCap = remainingCaps.get(step.policy) ?? initialCap(policyStep);
203	  const requestedPayout = totalPayout(step.incident.damages, policyStep);
204	  const payout = Math.min(requestedPayout, availableCap);
205	  const remainingCap = availableCap - payout;
206	  remainingCaps.set(step.policy, remainingCap);
207	  return { payout, remainingCap };
208	};
209	
210	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
211	  const remainingCaps = new Map<number, number>();
212	  return {
213	    results: scenario.steps.map((step, i) =>
214	      step.op === "quote"
215	        ? priceQuote(step, scenario.customer, countQuotesBefore(scenario.steps, i) > 0)
216	        : processClaim(step, scenario.steps, remainingCaps),
217	    ),
218	  };
219	};
